CREATE TABLE `activity_logs` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `shop_id` int(10) unsigned DEFAULT 1,
  `user_id` int(10) unsigned DEFAULT NULL,
  `user_name` varchar(100) DEFAULT NULL,
  `module` varchar(50) NOT NULL COMMENT 'employees, products, customers, orders, inventory, auth, settings',
  `action` varchar(50) NOT NULL COMMENT 'create, update, delete, login, logout, import, export',
  `target_id` int(10) unsigned DEFAULT NULL COMMENT 'ID của bản ghi bị tác động',
  `target_name` varchar(200) DEFAULT NULL COMMENT 'Tên/mô tả bản ghi',
  `details` text DEFAULT NULL COMMENT 'Chi tiết thay đổi (JSON)',
  `ip_address` varchar(50) DEFAULT NULL,
  `user_agent` varchar(500) DEFAULT NULL,
  `status` enum('success','error') NOT NULL DEFAULT 'success',
  `error_message` text DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_logs_user` (`user_id`),
  KEY `idx_logs_module` (`module`),
  KEY `idx_logs_action` (`action`),
  KEY `idx_logs_status` (`status`),
  KEY `idx_logs_created_at` (`created_at`),
  KEY `idx_logs_shop` (`shop_id`),
  CONSTRAINT `fk_logs_shop` FOREIGN KEY (`shop_id`) REFERENCES `shops` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=2248 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
