--
-- Table structure for table `customers`
--

DROP TABLE IF EXISTS `customers`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `customers` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `shop_id` int(10) unsigned NOT NULL DEFAULT 1,
  `name` varchar(100) NOT NULL,
  `phone` varchar(20) DEFAULT NULL,
  `email` varchar(100) DEFAULT NULL,
  `address` text DEFAULT NULL,
  `city` varchar(50) DEFAULT NULL,
  `district` varchar(50) DEFAULT NULL,
  `ward` varchar(50) DEFAULT NULL,
  `birthday` date DEFAULT NULL,
  `tier` enum('new','silver','gold','platinum','diamond') NOT NULL DEFAULT 'new',
  `total_spent` decimal(15,2) NOT NULL DEFAULT 0.00,
  `points_balance` int(11) NOT NULL DEFAULT 0 COMMENT 'Điểm tích lũy',
  `source` varchar(50) DEFAULT NULL COMMENT 'store/facebook/website/referral',
  `assigned_employee_id` int(10) unsigned DEFAULT NULL COMMENT 'Nhân viên phụ trách',
  `note` text DEFAULT NULL,
  `created_by` int(10) unsigned NOT NULL COMMENT 'Người tạo',
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_customers_phone` (`phone`),
  KEY `idx_customers_email` (`email`),
  KEY `idx_customers_tier` (`tier`),
  KEY `idx_customers_created_by` (`created_by`),
  KEY `idx_customers_assigned` (`assigned_employee_id`),
  KEY `idx_customers_shop` (`shop_id`),
  CONSTRAINT `fk_customers_assigned` FOREIGN KEY (`assigned_employee_id`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_customers_created_by` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`),
  CONSTRAINT `fk_customers_shop` FOREIGN KEY (`shop_id`) REFERENCES `shops` (`id`) ON DELETE NO ACTION
) ENGINE=InnoDB AUTO_INCREMENT=300 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `customers`
--

LOCK TABLES `customers` WRITE;
